import React from 'react';

function Experience() {
  return (
    <section id="experience" style={{ height: '100vh', padding: '50px', backgroundColor: '#c4c4c4' }}>
      <h1>Experience</h1>
      <ul>
        <li>
          <strong>Software Engineer</strong> - XYZ Company (2022-Present)
          <p>Developed full-stack web applications with React and Node.js.</p>
        </li>
        <li>
          <strong>Intern</strong> - ABC Corporation (2021-2022)
          <p>Worked on cloud solutions using AWS and Python.</p>
        </li>
        <li>
          <strong>BSc in Computer Science</strong> - University of XYZ (2017-2021)
        </li>
      </ul>
    </section>
  );
}

export default Experience;
